class Solution:
    def possibleBipartition(self, n: int, dislikes: List[List[int]]) -> bool:
        graph = [[] for _ in range(n + 1)]
        color = [0] * (n + 1)
        for a, b in dislikes:
            graph[a].append(b)
            graph[b].append(a)
        for i in range(1, n + 1):
            if color[i] == 0:
                if not self.dfs(graph, color, i, 1):
                    return False
        return True

    def dfs(self, graph, color, node, c):
        if color[node] != 0:
            return color[node] == c
        color[node] = c
        for neighbor in graph[node]:
            if not self.dfs(graph, color, neighbor, -c):
                return False
        return True
